# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from flask import Flask, request, abort
from web3 import Web3

app = Flask(__name__)
w3 = Web3(Web3.HTTPProvider('http://localhost:8545'))  # replace with your Ethereum node

@app.route('/auth', methods=['POST'])
def auth():
    data = request.json
    # Required fields from POST json: signature, message, user_address
    if not all (k in data for k in ("signature", "message", "user_address")):
        abort(400, 'Required fields: signature, message, user_address')

    signature = data['signature']
    message = data['message']
    user_address = data['user_address']

    message_hash = w3.keccak(text=message)
    recovered_address = w3.eth.account.recoverHash(message_hash, signature=signature)
    
    if recovered_address.lower() == user_address.lower():
        return {"auth": True}, 200
    else:
        return {"auth": False}, 401

if __name__ == "__main__":
    app.run(host='0.0.0.0', port=8000)